class Solution {
public:
    long long countGoodIntegers(int n, int k) {
        if (n == 1) {
            return (9 / k);
        }
        long long res = 0;
        for (int i = 1; i <= 9; i++) {
            int cnt[10] = {0};
            cnt[i]++;
            res += dfs(n - 1, k, cnt);
        }
        return res;
    }

    long long dfs(int n, int k, int cnt[10]) {
        if (n == 0) {
            int sum = 0;
            for (int i = 0; i <= 9; i++) {
                sum += cnt[i];
            }
            if (sum % 2 == 0) {
                for (int i = 1; i <= 9; i++) {
                    if (cnt[i] % 2 != 0) {
                        return 0;
                    }
                }
            } else {
                int odd = 0;
                for (int i = 1; i <= 9; i++) {
                    if (cnt[i] % 2 != 0) {
                        odd++;
                    }
                }
                if (odd > 1) {
                    return 0;
                }
            }
            int num = 0;
            for (int i = 0; i <= 9; i++) {
                num += cnt[i];
            }
            long long tmp = 1;
            for (int i = 1; i <= num / 2; i++) {
                tmp *= i;
            }
            for (int i = 1; i <= (num + 1) / 2; i++) {
                tmp *= i;
            }
            for (int i = 1; i <= num; i++) {
                tmp /= i;
            }
            for (int i = 0; i <= 9; i++) {
                int tmp2 = 1;
                for (int j = 1; j <= cnt[i]; j++) {
                    tmp2 *= j;
                }
                tmp /= tmp2;
            }
            if (num % k == 0) {
                return tmp;
            } else {
                return 0;
            }
        }
        long long res = 0;
        for (int i = 0; i <= 9; i++) {
            cnt[i]++;
            res += dfs(n - 1, k, cnt);
            cnt[i]--;
        }
        return res;
    }
};

